css:
@page {
  size: A4; margin: 14mm 16mm 20mm 16mm;
  @bottom-left { content: "Beispiel Industrieteile GmbH · Industriestraße 8 · 70565 Stuttgart \A Amtsgericht Stuttgart · HRB 654321 \A Geschäftsführer: Max Beispiel"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; vertical-align: top; padding-top: 4mm; }
  @bottom-center { content: "Seite " counter(page) " von " counter(pages); font-size: 6.5pt; color: #8a8a8a; white-space: nowrap; vertical-align: top; padding-top: 4mm; }
  @bottom-right { content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A IBAN DE89 3704 0044 0532 0130 00 · BIC COBADEFFXXX"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm; }
}

body { color: #16243b; font-family: 'Helvetica', 'Arial', sans-serif; }
.num { font-variant-numeric: tabular-nums; }
.mono { font-family: 'Courier New', 'Consolas', monospace; letter-spacing: -0.02em; }
.doc-header { display: none; }

/* Dark header band */
.in-band { display: flex; align-items: center; justify-content: space-between; background: #16243b; color: #fff; border-radius: 2mm; padding: 5mm 7mm; border-left: 3mm solid #f59e0b; }
.in-band__left { display: flex; align-items: center; gap: 5mm; }
.in-mark { height: 12mm; width: 12mm; display: block; }
.in-doctype { font-size: 8pt; letter-spacing: 0.34em; text-transform: uppercase; color: #f59e0b; font-weight: 700; }
.in-docno { font-size: 19pt; font-weight: 800; letter-spacing: 0.01em; }
.in-band__bc svg { height: 13mm; width: 52mm; }

/* Info grid */
.in-grid { display: flex; flex-wrap: wrap; border: 1px solid #d7dee8; border-radius: 2mm; margin: 6mm 0 4mm; }
.in-cell { flex: 1 1 33%; padding: 3mm 4mm; border-right: 1px solid #e6ebf1; border-bottom: 1px solid #e6ebf1; }
.in-cell:nth-child(3n) { border-right: none; }
.in-cell:nth-child(n+4) { border-bottom: none; }
.in-k { display: block; font-size: 6.8pt; letter-spacing: 0.16em; text-transform: uppercase; color: #7c8aa0; font-weight: 700; margin-bottom: 1mm; }
.in-v { font-size: 10.5pt; font-weight: 700; }

.in-ship { margin-bottom: 6mm; }
.in-ship .in-k { margin-bottom: 1.4mm; }
.in-addr { font-size: 10pt; }

/* Items */
.in-items { width: 100%; border-collapse: collapse; margin-bottom: 7mm; }
.in-items thead th { font-size: 7pt; letter-spacing: 0.1em; text-transform: uppercase; color: #fff; background: #16243b; font-weight: 700; text-align: left; padding: 2.4mm 3mm; }
.in-items tbody td { padding: 2.8mm 3mm; border-bottom: 1px solid #e6ebf1; vertical-align: top; }
.in-items tbody tr:nth-child(even) { background: #f6f8fb; }
.in-partial { background: #fff7ea !important; }
.in-c-pos { width: 11mm; color: #7c8aa0; }
.in-c-art { width: 30mm; font-size: 9.5pt; }
.in-c-num { width: 24mm; text-align: right; }
.in-charge { display: block; color: #7c8aa0; font-size: 8pt; margin-top: 0.8mm; }
.in-flag { font-size: 6.5pt; font-weight: 800; color: #fff; background: #f59e0b; border-radius: 1mm; padding: 0.3mm 1.4mm; letter-spacing: 0.05em; }
thead th.in-c-num { text-align: right; }

/* Footer */
.in-foot { display: flex; gap: 8mm; align-items: stretch; }
.in-pack { flex: 1 1 0; }
.in-packlist { margin: 1.6mm 0 0; padding-left: 4mm; font-size: 9pt; line-height: 1.6; }
.in-hint { font-size: 8pt; color: #6b7890; line-height: 1.45; margin-top: 3mm; max-width: 100mm; }
.in-qc { flex: 0 0 60mm; border: 1.5px solid #16243b; border-radius: 2mm; padding: 4mm; }
.in-qc__title { font-size: 8pt; letter-spacing: 0.14em; text-transform: uppercase; font-weight: 800; margin-bottom: 3mm; }
.in-qc__check { font-size: 9.5pt; margin-bottom: 2mm; display: flex; align-items: center; gap: 2.5mm; }
.in-box { width: 4mm; height: 4mm; border: 1.4px solid #16243b; border-radius: 0.8mm; display: inline-block; }
.in-qc__sig { margin-top: 5mm; }
.in-qc__rule { display: block; border-top: 1px solid #16243b; height: 8mm; margin-bottom: 1.2mm; }
.in-siglabel { font-size: 7.5pt; color: #7c8aa0; }
